    let config = flow.remoteConfigs.first(where: { $0.locale == "en" })
        ?? flow.remoteConfigs.first
    let showPaywall = config?.dictionary?["show_paywall"] as? Bool ?? true

    if showPaywall {
        // render the flow or paywall
    }
} catch {
    // handle the error
}
```

